$ErrorActionPreference = "Stop"

$ruta = Join-Path (Get-Location) "UI\Form1.TabInicio.cs"

if (-not (Test-Path $ruta)) {
    throw "No se encontro UI\Form1.TabInicio.cs."
}

$contenido = [System.IO.File]::ReadAllText($ruta)

if ($contenido.Contains("private Control CrearDashboardInicioOthalart()")) {
    Write-Host "El dashboard ya parece estar aplicado." -ForegroundColor Yellow
    exit 0
}

$firma = "        private void ConstruirTabInicio(TabPage tab)"
$inicio = $contenido.IndexOf($firma, [StringComparison]::Ordinal)

if ($inicio -lt 0) {
    throw "No se encontro ConstruirTabInicio(TabPage tab)."
}

$llaveInicial = $contenido.IndexOf("{", $inicio, [StringComparison]::Ordinal)
$profundidad = 0
$fin = -1

for ($i = $llaveInicial; $i -lt $contenido.Length; $i++) {
    if ($contenido[$i] -eq '{') {
        $profundidad++
    }
    elseif ($contenido[$i] -eq '}') {
        $profundidad--
        if ($profundidad -eq 0) {
            $fin = $i
            break
        }
    }
}

if ($fin -lt 0) {
    throw "No se encontro el final de ConstruirTabInicio."
}

$bytes = [Convert]::FromBase64String("")
$nuevoBloque = [System.Text.Encoding]::UTF8.GetString($bytes)

$contenidoNuevo =
    $contenido.Substring(0, $inicio) +
    $nuevoBloque +
    $contenido.Substring($fin + 1)

$backup = "$ruta.backup_dashboard_determinista_$(Get-Date -Format 'yyyyMMdd_HHmmss')"
Copy-Item $ruta $backup

$utf8ConBom = New-Object System.Text.UTF8Encoding($true)
[System.IO.File]::WriteAllText($ruta, $contenidoNuevo, $utf8ConBom)

Write-Host ""
Write-Host "Dashboard de inicio aplicado correctamente." -ForegroundColor Green
Write-Host "Backup: $backup"
Write-Host ""
Write-Host 'Compila con: dotnet build "OthalartSoftware v1.0.csproj" -c Debug'
